/*
# Fix formula deduplication — clear and re-seed with proper village mapping

## Plain English
The previous formula seed used CROSS JOIN which duplicated each formula across
ALL villages in a kingdom. This migration clears all formula rows and re-seeds
them with each formula mapped to its SPECIFIC topic village via a vslug join
key. One row per formula, attached to the correct village.
*/

DELETE FROM formulas;

-- Re-seed Kingdom of Numbers formulas with village slug mapping
INSERT INTO formulas (kingdom_id, village_id, topic_name, formula_name, formula_text, description, category, example, tags)
SELECT k.id, v.id, v.name, f.fname, f.ftext, f.fdesc, f.fcat, f.fex, f.ftags
FROM kingdoms k
JOIN villages v ON v.kingdom_id = k.id AND k.slug = 'numbers'
JOIN (VALUES
  ('numbers-even-numbers', 'Even Number Test', 'n % 2 = 0', 'A number is even if divisible by 2 with no remainder', 'Number System', '14 % 2 = 0, so 14 is even', ARRAY['even','divisibility','parity']),
  ('numbers-odd-numbers', 'Odd Number Test', 'n % 2 != 0', 'A number is odd if division by 2 leaves remainder 1', 'Number System', '15 % 2 = 1, so 15 is odd', ARRAY['odd','divisibility','parity']),
  ('numbers-number-properties', 'Divisibility by 3', 'Sum of digits divisible by 3', 'A number is divisible by 3 if the sum of its digits is divisible by 3', 'Number System', '123: 1+2+3=6, 6/3=2', ARRAY['divisibility','3']),
  ('numbers-divisibility-rules', 'Divisibility by 4', 'Last two digits divisible by 4', 'A number is divisible by 4 if its last two digits form a number divisible by 4', 'Number System', '1316: 16/4=4', ARRAY['divisibility','4']),
  ('numbers-divisibility-rules', 'Divisibility by 5', 'Last digit is 0 or 5', 'A number is divisible by 5 if it ends in 0 or 5', 'Number System', '235 ends in 5', ARRAY['divisibility','5']),
  ('numbers-divisibility-rules', 'Divisibility by 6', 'Divisible by both 2 and 3', 'A number is divisible by 6 if divisible by both 2 and 3', 'Number System', '72: even and 7+2=9 div by 3', ARRAY['divisibility','6']),
  ('numbers-divisibility-rules', 'Divisibility by 8', 'Last three digits divisible by 8', 'A number is divisible by 8 if its last three digits form a number divisible by 8', 'Number System', '3712: 712/8=89', ARRAY['divisibility','8']),
  ('numbers-divisibility-rules', 'Divisibility by 9', 'Sum of digits divisible by 9', 'A number is divisible by 9 if the sum of its digits is divisible by 9', 'Number System', '459: 4+5+9=18', ARRAY['divisibility','9']),
  ('numbers-divisibility-rules', 'Divisibility by 11', 'Alternating digit sum divisible by 11', 'Subtract and add digits alternately', 'Number System', '121: 1-2+1=0', ARRAY['divisibility','11']),
  ('numbers-hcf', 'HCF via Euclid', 'HCF(a,b) = HCF(b, a mod b)', 'Euclidean algorithm for highest common factor', 'Number System', 'HCF(48,18)=6', ARRAY['hcf','euclid','gcd']),
  ('numbers-lcm', 'LCM x HCF', 'a x b = HCF(a,b) x LCM(a,b)', 'Product of two numbers equals product of HCF and LCM', 'Number System', '12*18=216=6*36', ARRAY['lcm','hcf','product']),
  ('numbers-remainders', 'Remainder Theorem', '(a+b) mod n = ((a mod n)+(b mod n)) mod n', 'Remainder of sum equals sum of remainders mod n', 'Number System', '(17+13) mod 5 = 0', ARRAY['remainder','modular']),
  ('numbers-cyclicity', 'Cyclicity of 2', 'Unit digit cycles 2,4,8,6 every 4 powers', 'Powers of 2 cycle unit digit with period 4', 'Number System', '2^1=2, 2^2=4, 2^3=8, 2^4=16', ARRAY['cyclicity','unit-digit','powers']),
  ('numbers-cyclicity', 'Cyclicity of 3', 'Unit digit cycles 3,9,7,1 every 4 powers', 'Powers of 3 cycle unit digit with period 4', 'Number System', '3^1=3, 3^2=9, 3^3=27, 3^4=81', ARRAY['cyclicity','unit-digit','powers']),
