  ('numbers-factors', 'Number of Factors', 'Product of (exponent+1) for each prime factor', 'If n = p^a * q^b, factors = (a+1)(b+1)', 'Number System', '12 = 2^2 * 3^1, factors = 6', ARRAY['factors','prime']),
