  ('numbers-number-properties', 'Sum of First N Natural Numbers', 'N(N+1)/2', 'Triangular number formula', 'Number System', 'Sum 1..100 = 5050', ARRAY['sum','series','natural']),
  ('numbers-number-properties', 'Sum of First N Squares', 'N(N+1)(2N+1)/6', 'Sum of squares of first n natural numbers', 'Number System', 'Sum 1^2..5^2 = 55', ARRAY['sum','squares','series']),
  ('numbers-number-properties', 'Sum of First N Cubes', '(N(N+1)/2)^2', 'Sum of cubes equals square of triangular number', 'Number System', 'Sum 1^3..4^3 = 100', ARRAY['sum','cubes','series']),
