  ('numbers-mixtures', 'Mixture Replacement', 'Final = Initial x (1 - R/V)^n', 'Pure quantity after n replacements', 'Arithmetic', 'Replace 1/3 of 9L 3x -> 8/3 L', ARRAY['mixture','replacement']),
  ('numbers-time-work', 'Work Rate', 'Work = Rate x Time', 'Fundamental work formula', 'Speed & Work', 'Rate 1/6 job/hr, 3 hrs -> 1/2 job', ARRAY['work','rate']),
  ('numbers-time-work', 'Combined Work', '1/T = 1/A + 1/B', 'Time for two workers together', 'Speed & Work', 'A=6hr, B=12hr -> T=4', ARRAY['work','combined']),
